css:
.loader {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  height: 52px;
  color: #6366f1;
}
.loader i {
  width: 7px;
  height: 40px;
  border-radius: 999px;
  background: currentColor;
  animation: wave 1s ease-in-out infinite;
}
.loader i:nth-child(2) { animation-delay: 0.1s; }
.loader i:nth-child(3) { animation-delay: 0.2s; }
.loader i:nth-child(4) { animation-delay: 0.3s; }
.loader i:nth-child(5) { animation-delay: 0.4s; }
@keyframes wave {
  0%, 100% { transform: scaleY(0.38); opacity: 0.38; }
  50% { transform: scaleY(1); opacity: 1; }
}
